create migrations

-- Extend scheduled_posts for X
alter table public.scheduled_posts
  add column if not exists x_post_id text,
  add column if not exists x_account_id text,
  add column if not exists retries int not null default 0;

-- Add 'x' to publish_surface if it's a text[] (check enum first)
-- If publish_surface is text[], just start inserting rows with publish_surface = ARRAY['x']

-- Dedup index: one pending post per match per surface
create unique index if not exists scheduled_posts_match_x_dedup
  on public.scheduled_posts (match_id, (publish_surface::text))
  where status not in ('failed', 'draft')
    and match_id is not null;

-- Worker poll index
create index if not exists scheduled_posts_worker_x_idx
  on public.scheduled_posts (status, scheduled_for)
  where status in ('pending', 'scheduled');

-- The ONE genuinely new table
create table public.post_policies (
  id                          uuid primary key default gen_random_uuid(),
  league_id                   uuid references public.leagues_info(id) on delete cascade unique not null,
  auto_post_verified_games    bool not null default false,
  include_box_score_link      bool not null default true,
  include_hashtags            bool not null default true,
  min_stat_threshold          int not null default 0,
  updated_at                  timestamptz not null default now()
);
alter table public.post_policies enable row level security;
create policy "admin_all" on public.post_policies
  using (auth.jwt() ->> 'role' in ('admin', 'commissioner', 'superadmin'));

-- X credentials go in webhook_config (already exists, per-league KV)
-- insert into webhook_config (league_id, key, value) values (:league_id, 'x_access_token', :token);
-- insert into webhook_config (league_id, key, value) values (:league_id, 'x_access_secret', :secret);


create or replace function public.enqueue_verified_game_post()
returns trigger language plpgsql security definer as $$
declare
  policy post_policies%rowtype;
  story  text;
begin
  if new.verified = true and (old.verified is distinct from true) then
    select * into policy from post_policies where league_id = new.league_id;

    if found and policy.auto_post_verified_games then
      -- pull existing game story as body if available
      select content into story from match_game_stories where match_id = new.id;

      insert into scheduled_posts (
        post_type, status, match_id, caption, publish_surface, scheduled_for
      )
      values (
        'verified_game',
        'pending',
        new.id,
        story,           -- null is fine — worker will build it
        ARRAY['x'],
        now()
      )
      on conflict do nothing;
    end if;
  end if;
  return new;
end;
$$;
